INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  10,
  3,
  3,
  'Which summary best fits the movement of 2 Samuel 3?',
  '["Abner turns against Ish-bosheth and promises to bring all Israel to David, but Joab kills him in revenge for Asahel''s death. David distances himself from the murder, laments Abner publicly, and refuses to let his own house appear guilty. The chapter strengthens David''s legitimacy while exposing the violence around him.", "David seeks the LORD and goes to Hebron, where Judah anoints him king, while Abner makes Ish-bosheth king over the rest of Israel. The chapter''s conflicts begin with a brutal contest at Gibeon and end with Asahel''s death and Joab''s hard-won victory. It shows a kingdom split before it is unified.", "When Ish-bosheth''s captains bring him the news of Abner''s death, two men murder him in his house and flee with his head. David again refuses to reward violence, executing the assassins and honoring the slain king with burial. The chapter removes Saul''s last rival by treachery rather than battle.", "The tribes finally come together and anoint David king over all Israel at Hebron. David captures Jerusalem from the Jebusites, makes it his stronghold, and grows stronger as the LORD establishes him. Philistine attacks follow, but David seeks God''s guidance and wins decisive victories."]'::jsonb,
  'Abner turns against Ish-bosheth and promises to bring all Israel to David, but Joab kills him in revenge for Asahel''s death. David distances himself from the murder, laments Abner publicly, and refuses to let his own house appear guilty. The chapter strengthens David''s legitimacy while exposing the violence around him.',
  'This summary captures the movement of 2 Samuel 3 (2 Samuel 3:1-21-2 Samuel 3:1-21).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 10
    AND chapter = 3
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 2 Samuel 3?'
);

