INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  10,
  16,
  3,
  'Which summary best fits the movement of 2 Samuel 16?',
  '["As David escapes, Ziba opportunistically claims Mephibosheth''s loyalty, and Shimei curses David with stones and dust. David refuses revenge and leaves judgment to God while Hushai arrives in Jerusalem to counter Ahithophel''s counsel. The chapter is full of mixed motives, but David keeps moving with restraint.", "Absalom wins hearts in Israel and stages a conspiracy that forces David to flee Jerusalem barefoot and grieving. Loyal servants, priests, and counselors all face hard choices as the king leaves the city. The chapter shows the cost of sin rippling outward into public collapse.", "Ahithophel gives Absalom a ruthless plan to strike David immediately, but Hushai gives a slower counsel designed to buy David time. The warning is carried through loyal messengers, and when Ahithophel sees his counsel rejected he goes home and hangs himself. The chapter shows wisdom fighting wisdom while God protects David through delay.", "David''s forces defeat Absalom''s army in the forest of Ephraim, and Absalom is caught in an oak by his hair. Joab ignores David''s plea and kills Absalom, ending the rebellion with a public heap of stones and a private father''s grief. The chapter is a grim climax where victory and sorrow collide."]'::jsonb,
  'As David escapes, Ziba opportunistically claims Mephibosheth''s loyalty, and Shimei curses David with stones and dust. David refuses revenge and leaves judgment to God while Hushai arrives in Jerusalem to counter Ahithophel''s counsel. The chapter is full of mixed motives, but David keeps moving with restraint.',
  'This summary captures the movement of 2 Samuel 16 (2 Samuel 16:1-4-2 Samuel 16:1-14).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 10
    AND chapter = 16
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 2 Samuel 16?'
);

