INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  10,
  18,
  3,
  'Which summary best fits the movement of 2 Samuel 18?',
  '["David''s forces defeat Absalom''s army in the forest of Ephraim, and Absalom is caught in an oak by his hair. Joab ignores David''s plea and kills Absalom, ending the rebellion with a public heap of stones and a private father''s grief. The chapter is a grim climax where victory and sorrow collide.", "Ahithophel gives Absalom a ruthless plan to strike David immediately, but Hushai gives a slower counsel designed to buy David time. The warning is carried through loyal messengers, and when Ahithophel sees his counsel rejected he goes home and hangs himself. The chapter shows wisdom fighting wisdom while God protects David through delay.", "Joab rebukes David for grieving so hard that he seems to dishonor the men who saved him, and the king returns to Jerusalem after political confusion in Judah and Israel. The chapter includes tensions with Mephibosheth, the faithful support of Barzillai, and disputes over who truly stood by the king. David comes back to power, but the kingdom is still strained.", "Sheba son of Bichri sparks a northern revolt, and David''s new general Amasa is murdered by Joab under a pretense of greeting. The rebellion is contained after Joab pursues Sheba to Abel Beth-maacah, where a wise woman negotiates peace by handing over Sheba''s head. The chapter shows how fragile David''s restored kingdom still is."]'::jsonb,
  'David''s forces defeat Absalom''s army in the forest of Ephraim, and Absalom is caught in an oak by his hair. Joab ignores David''s plea and kills Absalom, ending the rebellion with a public heap of stones and a private father''s grief. The chapter is a grim climax where victory and sorrow collide.',
  'This summary captures the movement of 2 Samuel 18 (2 Samuel 18:1-18-2 Samuel 18:19-33).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 10
    AND chapter = 18
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 2 Samuel 18?'
);

