INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  10,
  19,
  3,
  'Which summary best fits the movement of 2 Samuel 19?',
  '["Joab rebukes David for grieving so hard that he seems to dishonor the men who saved him, and the king returns to Jerusalem after political confusion in Judah and Israel. The chapter includes tensions with Mephibosheth, the faithful support of Barzillai, and disputes over who truly stood by the king. David comes back to power, but the kingdom is still strained.", "David''s forces defeat Absalom''s army in the forest of Ephraim, and Absalom is caught in an oak by his hair. Joab ignores David''s plea and kills Absalom, ending the rebellion with a public heap of stones and a private father''s grief. The chapter is a grim climax where victory and sorrow collide.", "Sheba son of Bichri sparks a northern revolt, and David''s new general Amasa is murdered by Joab under a pretense of greeting. The rebellion is contained after Joab pursues Sheba to Abel Beth-maacah, where a wise woman negotiates peace by handing over Sheba''s head. The chapter shows how fragile David''s restored kingdom still is.", "A famine reveals bloodguilt against the Gibeonites, so David hands over descendants of Saul and the land receives relief after justice is done. Rizpah''s vigil over the bodies moves David to gather Saul and Jonathan''s bones, and the chapter closes with battles against Philistine giants. Mercy, memory, and continued warfare all stand together here."]'::jsonb,
  'Joab rebukes David for grieving so hard that he seems to dishonor the men who saved him, and the king returns to Jerusalem after political confusion in Judah and Israel. The chapter includes tensions with Mephibosheth, the faithful support of Barzillai, and disputes over who truly stood by the king. David comes back to power, but the kingdom is still strained.',
  'This summary captures the movement of 2 Samuel 19 (2 Samuel 19:1-15-2 Samuel 19:1-15).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 10
    AND chapter = 19
    AND difficulty_stage = 3
    AND prompt = 'Which summary best fits the movement of 2 Samuel 19?'
);

