INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  10,
  21,
  5,
  'What final perspective best fits 2 Samuel 21?',
  '["A famine reveals bloodguilt against the Gibeonites, so David hands over descendants of Saul and the land receives relief after justice is done. Rizpah''s vigil over the bodies moves David to gather Saul and Jonathan''s bones, and the chapter closes with battles against Philistine giants. Mercy, memory, and continued warfare all stand together here.", "David sings a long psalm of rescue, praising the LORD as rock, fortress, and deliverer who answered him in distress. The song celebrates God''s intervention in battle, his perfect ways, and his care for the humble. It becomes David''s theological summary of why he survived and ruled.", "David seeks the LORD and goes to Hebron, where Judah anoints him king, while Abner makes Ish-bosheth king over the rest of Israel. The chapter''s conflicts begin with a brutal contest at Gibeon and end with Asahel''s death and Joab''s hard-won victory. It shows a kingdom split before it is unified.", "Abner turns against Ish-bosheth and promises to bring all Israel to David, but Joab kills him in revenge for Asahel''s death. David distances himself from the murder, laments Abner publicly, and refuses to let his own house appear guilty. The chapter strengthens David''s legitimacy while exposing the violence around him."]'::jsonb,
  'A famine reveals bloodguilt against the Gibeonites, so David hands over descendants of Saul and the land receives relief after justice is done. Rizpah''s vigil over the bodies moves David to gather Saul and Jonathan''s bones, and the chapter closes with battles against Philistine giants. Mercy, memory, and continued warfare all stand together here.',
  'This final perspective fits 2 Samuel 21 (2 Samuel 21:1-14-2 Samuel 21:15-22).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 10
    AND chapter = 21
    AND difficulty_stage = 5
    AND prompt = 'What final perspective best fits 2 Samuel 21?'
);

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
