INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  10,
  22,
  4,
  'Which summary line best expresses the narrative function of 2 Samuel 22?',
  '["David sings a long psalm of rescue, praising the LORD as rock, fortress, and deliverer who answered him in distress. The song celebrates God''s intervention in battle, his perfect ways, and his care for the humble. It becomes David''s theological summary of why he survived and ruled.", "David''s last words celebrate the righteous ruler who governs in the fear of God and shines like the morning light. The chapter then lists his mighty men, honoring the loyal warriors who shared his hard-won victories. It closes David''s life story with both ideal kingship and remembered companionship.", "David orders a census, then recognizes that the counting was sinful and chooses to fall into the LORD''s hand rather than man''s. A plague strikes Israel until David builds an altar on Araunah''s threshing floor and offers sacrifices. The chapter ends with judgment checked by mercy and a site that will later matter deeply in Israel''s worship life.", "A messenger brings David news of Saul and Jonathan''s death, hoping for reward, but instead he meets grief and judgment. David composes a lament that honors Saul as Israel''s fallen king and Jonathan as his beloved friend. The chapter begins David''s reign with sorrow rather than triumph."]'::jsonb,
  'David sings a long psalm of rescue, praising the LORD as rock, fortress, and deliverer who answered him in distress. The song celebrates God''s intervention in battle, his perfect ways, and his care for the humble. It becomes David''s theological summary of why he survived and ruled.',
  'This summary line expresses the narrative function of 2 Samuel 22.'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 10
    AND chapter = 22
    AND difficulty_stage = 4
    AND prompt = 'Which summary line best expresses the narrative function of 2 Samuel 22?'
);

