INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  10,
  22,
  5,
  'What final perspective best fits 2 Samuel 22?',
  '["David sings a long psalm of rescue, praising the LORD as rock, fortress, and deliverer who answered him in distress. The song celebrates God''s intervention in battle, his perfect ways, and his care for the humble. It becomes David''s theological summary of why he survived and ruled.", "David''s last words celebrate the righteous ruler who governs in the fear of God and shines like the morning light. The chapter then lists his mighty men, honoring the loyal warriors who shared his hard-won victories. It closes David''s life story with both ideal kingship and remembered companionship.", "Abner turns against Ish-bosheth and promises to bring all Israel to David, but Joab kills him in revenge for Asahel''s death. David distances himself from the murder, laments Abner publicly, and refuses to let his own house appear guilty. The chapter strengthens David''s legitimacy while exposing the violence around him.", "When Ish-bosheth''s captains bring him the news of Abner''s death, two men murder him in his house and flee with his head. David again refuses to reward violence, executing the assassins and honoring the slain king with burial. The chapter removes Saul''s last rival by treachery rather than battle."]'::jsonb,
  'David sings a long psalm of rescue, praising the LORD as rock, fortress, and deliverer who answered him in distress. The song celebrates God''s intervention in battle, his perfect ways, and his care for the humble. It becomes David''s theological summary of why he survived and ruled.',
  'This final perspective fits 2 Samuel 22 (2 Samuel 22:1-7-2 Samuel 22:1-51).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 10
    AND chapter = 22
    AND difficulty_stage = 5
    AND prompt = 'What final perspective best fits 2 Samuel 22?'
);

INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  10,
  22,
  5,
  'Which advanced summary best matches 2 Samuel 22?',
  '["David sings a long psalm of rescue, praising the LORD as rock, fortress, and deliverer who answered him in distress. The song celebrates God''s intervention in battle, his perfect ways, and his care for the humble. It becomes David''s theological summary of why he survived and ruled.", "A famine reveals bloodguilt against the Gibeonites, so David hands over descendants of Saul and the land receives relief after justice is done. Rizpah''s vigil over the bodies moves David to gather Saul and Jonathan''s bones, and the chapter closes with battles against Philistine giants. Mercy, memory, and continued warfare all stand together here.", "David''s last words celebrate the righteous ruler who governs in the fear of God and shines like the morning light. The chapter then lists his mighty men, honoring the loyal warriors who shared his hard-won victories. It closes David''s life story with both ideal kingship and remembered companionship.", "David seeks the LORD and goes to Hebron, where Judah anoints him king, while Abner makes Ish-bosheth king over the rest of Israel. The chapter''s conflicts begin with a brutal contest at Gibeon and end with Asahel''s death and Joab''s hard-won victory. It shows a kingdom split before it is unified."]'::jsonb,
  'David sings a long psalm of rescue, praising the LORD as rock, fortress, and deliverer who answered him in distress. The song celebrates God''s intervention in battle, his perfect ways, and his care for the humble. It becomes David''s theological summary of why he survived and ruled.',
  'This advanced summary best matches 2 Samuel 22 (2 Samuel 22:1-7-2 Samuel 22:1-51).'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 10
    AND chapter = 22
    AND difficulty_stage = 5
    AND prompt = 'Which advanced summary best matches 2 Samuel 22?'
);

